def most_common_word(s):
    if not s:
        return ''

    words = s.lower().split()
    word_count = {}
    max_count = 0

    for word in words:
        if word in word_count:
            word_count[word] += 1
        else:
            word_count[word] = 1

        if word_count[word] > max_count:
            max_count = word_count[word]

    most_common_words = [word for word, count in word_count.items() if count == max_count]
    return min(most_common_words)
